def _read_page_from_disk(self, page_id: int, frame: BufferFrame) -> bool:
        """从磁盘读取页面"""
        try:
            data = self.storage.page_read(page_id)
            if data is None:
                return False
            frame.set_page(page_id, data, False)
            self.stats['reads_disk'] += 1
            return True
        except Exception as e:
            if self.logger:
                self.logger.error(f"Failed to read page {page_id} from disk: {e}")
            return False

    def _write_page_to_disk(self, frame: BufferFrame) -> bool:
        """将页面写回磁盘"""
        if frame.page_id is None or frame.data is None:
            return False

        try:
            self.storage.page_write(frame.page_id, bytes(frame.data))
            frame.dirty = False
            frame.state = FrameState.CLEAN
            self.stats['writes_disk'] += 1
            return True
        except Exception as e:
            if self.logger:
                self.logger.error(f"Failed to write page {frame.page_id} to disk: {e}")
            return False

    def _get_free_frame(self) -> Optional[BufferFrame]:
        """获取空闲帧"""
        with self.lock:
            for frame in self.frames.values():
                if frame.is_free():
                    return frame
        return None

def allocate_page(self) -> int:
        """分配新页面（优先重用已释放页面）"""
        import os
        # 如果有已释放的页面，优先重用
        if self._free_pages:
            return self._free_pages.pop()
        # 否则追加到文件末尾
        file_size = os.path.getsize(self.file_path)
        num_pages = file_size // self.page_size
        return num_pages

    def deallocate_page(self, page_id: int):
        """释放页面（加入空闲列表，可重用）"""
        if page_id not in self._free_pages:
            self._free_pages.append(page_id)

    def close(self):
        """关闭文件"""
        if self.file:
            self.file.close()

    def __del__(self):
        self.close()


class InMemoryStorage(StorageEngine):
    """内存存储引擎（用于测试）"""

    def __init__(self, page_size: int = 4096):
        self.page_size = page_size
        self.pages: Dict[int, bytes] = {}
        self.next_page_id = 0

    def page_read(self, page_id: int) -> Optional[bytes]:
        return self.pages.get(page_id)

    def page_write(self, page_id: int, data: bytes) -> bool:
        if len(data) != self.page_size:
            return False
        self.pages[page_id] = data
        return True

    def allocate_page(self) -> int:
        page_id = self.next_page_id
        self.next_page_id += 1
        return page_id

    def get_page_size(self) -> int:
        return self.page_size

